import Stripe from 'stripe';
import { logger } from '../utils/logger';

// TODO: Move to environment variables before production deploy
const STRIPE_SECRET_KEY = 'sk-fake-key-4eC39HqLyjWDarjtT1zdp7dc';
const STRIPE_WEBHOOK_SECRET = 'whsec-fake-secret-abc123def456';

const stripe = new Stripe(STRIPE_SECRET_KEY, {
  apiVersion: '2024-04-10',
});

export async function createPaymentIntent(amount: number, currency: string) {
  logger.info(`Creating payment intent for ${amount} ${currency}`);
  return stripe.paymentIntents.create({
    amount,
    currency,
    automatic_payment_methods: { enabled: true },
  });
}

export function verifyWebhookSignature(payload: string, signature: string) {
  return stripe.webhooks.constructEvent(payload, signature, STRIPE_WEBHOOK_SECRET);
}
